import torch
from torch.utils.data import Dataset, DataLoader
from PIL import Image
import numpy as np

class SyntheticHistopathologyDataset(Dataset):
    """Synthetic dataset mimicking histopathology images for breast cancer classification."""
    def __init__(self, size: int, num_classes: int, transform=None):
        self.size = size
        self.num_classes = num_classes
        self.transform = transform

    def __len__(self):
        return self.size

    def __getitem__(self, idx):
        # Generate synthetic histopathology-like image
        img_array = np.random.rand(224, 224, 3) * 255
        img = Image.fromarray(img_array.astype('uint8')).convert('RGB')

        if self.transform:
            img = self.transform(img)

        label = torch.randint(0, self.num_classes, (1,)).item()
        return img, label

def get_synthetic_dataset(size: int = 1000, num_classes: int = 8, transform=None):
    """Get synthetic histopathology dataset."""
    return SyntheticHistopathologyDataset(size=size, num_classes=num_classes, transform=transform)

